#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int countDivisors(long long n) {
    int count = 0;
    for (long long i = 1; i * i <= n; i++) {
        if (n % i == 0) {
            if (n / i == i) {
                count++;
            } else {
                count += 2;
            }
        }
    }
    return count;
}

int isPrime(int n) {
    if (n <= 1) return 0;
    if (n == 2) return 1;
    if (n % 2 == 0) return 0;
    for (int i = 3; i * i <= n; i += 2) {
        if (n % i == 0) return 0;
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        long long P[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &P[i]);
        }
        int supporters = 0;
        long long supporterPosts[N];
        for (int i = 0; i < N; i++) {
            int divisors = countDivisors(P[i]);
            if (isPrime(divisors)) {
                supporterPosts[supporters++] = P[i];
            }
        }
        if (supporters == 0) {
            printf("No supporter found.\n");
        } else {
            for (int i = 0; i < supporters; i++) {
                for (int j = i + 1; j < supporters; j++) {
                    if (supporterPosts[i] < supporterPosts[j]) {
                        long long temp = supporterPosts[i];
                        supporterPosts[i] = supporterPosts[j];
                        supporterPosts[j] = temp;
                    }
                }
            }
            for (int i = 0; i < supporters; i++) {
                int rank = 1;
                for (int j = 0; j < N; j++) {
                    if (P[j] > supporterPosts[i]) {
                        rank++;
                    }
                }
                printf("%d ", rank);
            }
            printf("\n");
        }
    }
    return 0;
}

